def widest_water_reservoir(heights):
    left, right = 0, len(heights) - 1
    best = 0
    while left < right:
        h = min(heights[left], heights[right])
        width = right - left
        best = max(best, h * width)
        if heights[left] < heights[right]:
            left += 1
        else:
            right -= 1
    return best

